using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train and register the model at startup
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var data = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" strings to a boolean Label column
var labelLookup = mlContext.Data.LoadFromEnumerable(new[]
{
    new LabelMapping { ChurnedText = "Yes", Label = true },
    new LabelMapping { ChurnedText = "No", Label = false }
});

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", labelLookup, labelLookup.Schema["ChurnedText"], labelLookup.Schema["Label"],
        inputColumnName: nameof(CustomerData.ChurnedText))
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age), nameof(CustomerData.Income),
        "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

// With very small datasets, train on all data and skip evaluation
var rowCount = data.GetColumn<float>(nameof(CustomerData.Age)).Count();
if (rowCount >= 20)
